import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { useLocation, useNavigate, useParams } from "react-router-dom";
import { Bus, PassengerDetail, SavedPassengerProfile, Seat } from "../types";

const API_BASE = "http://localhost:5000/api";
const MAX_SEATS = 4;
const SAVED_PASSENGERS_KEY = "bus-booking-saved-passengers";

type PassengerForm = {
  name: string;
  age: string;
  gender: string;
};

const SeatSelectionPage: React.FC = () => {
  const { busId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();

  const [bus, setBus] = useState<Bus | null>(null);
  const [selectedSeats, setSelectedSeats] = useState<number[]>([]);
  const [passengerForms, setPassengerForms] = useState<Record<number, PassengerForm>>({});
  const [savedPassengers, setSavedPassengers] = useState<SavedPassengerProfile[]>([]);
  const [boardingPoint, setBoardingPoint] = useState("");
  const [droppingPoint, setDroppingPoint] = useState("");
  const [seatLimitMessage, setSeatLimitMessage] = useState("");
  const [travellerMessage, setTravellerMessage] = useState("");
  const [loading, setLoading] = useState(true);

  const travelDate = useMemo(() => new URLSearchParams(location.search).get("date") || "", [location.search]);

  useEffect(() => {
    try {
      const raw = window.localStorage.getItem(SAVED_PASSENGERS_KEY);
      if (!raw) return;
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        setSavedPassengers(parsed);
      }
    } catch (error) {
      console.error("Failed to load saved passengers", error);
    }
  }, []);

  useEffect(() => {
    const fetchBus = async () => {
      if (!busId) return;
      try {
        const suffix = travelDate ? `?date=${encodeURIComponent(travelDate)}` : "";
        const response = await axios.get<Bus>(`${API_BASE}/buses/${busId}${suffix}`);
        setBus(response.data);
        setBoardingPoint(response.data.boardingPoints[0] || "");
        setDroppingPoint(response.data.droppingPoints[0] || "");
      } catch (error) {
        console.error("Failed to fetch bus", error);
      } finally {
        setLoading(false);
      }
    };

    fetchBus();
  }, [busId, travelDate]);

  const seatRows = useMemo(() => {
    if (!bus) return [];
    const sorted = [...bus.seats].sort((a, b) => a.seatNumber - b.seatNumber);
    const rows: Seat[][] = [];

    for (let i = 0; i < sorted.length; i += 4) {
      rows.push(sorted.slice(i, i + 4));
    }

    return rows;
  }, [bus]);

  const totalPrice = useMemo(() => {
    if (!bus) return 0;
    return selectedSeats.length * bus.price;
  }, [bus, selectedSeats]);

  const availableSeatCount = useMemo(() => {
    return bus ? bus.seats.filter((seat) => seat.isAvailable).length : 0;
  }, [bus]);

  const allPassengerDetailsFilled = useMemo(() => {
    if (selectedSeats.length === 0) return false;

    return selectedSeats.every((seatNumber) => {
      const form = passengerForms[seatNumber];
      if (!form) return false;
      return Boolean(form.name.trim() && form.age && Number(form.age) > 0 && form.gender);
    });
  }, [selectedSeats, passengerForms]);

  const canContinueToPayment = useMemo(() => {
    return (
      selectedSeats.length >= 1 &&
      selectedSeats.length <= MAX_SEATS &&
      allPassengerDetailsFilled &&
      Boolean(boardingPoint) &&
      Boolean(droppingPoint)
    );
  }, [allPassengerDetailsFilled, boardingPoint, droppingPoint, selectedSeats.length]);

  const persistSavedPassengers = (nextProfiles: SavedPassengerProfile[]) => {
    setSavedPassengers(nextProfiles);
    window.localStorage.setItem(SAVED_PASSENGERS_KEY, JSON.stringify(nextProfiles));
  };

  const toggleSeat = (seatNumber: number, isAvailable: boolean) => {
    if (!isAvailable) return;

    const alreadySelected = selectedSeats.includes(seatNumber);
    if (!alreadySelected && selectedSeats.length >= MAX_SEATS) {
      setSeatLimitMessage("You can book a maximum of 4 seats per booking.");
      return;
    }

    setSeatLimitMessage("");
    setTravellerMessage("");
    setSelectedSeats((prev) => {
      if (prev.includes(seatNumber)) {
        const updated = prev.filter((item) => item !== seatNumber);
        setPassengerForms((current) => {
          const copy = { ...current };
          delete copy[seatNumber];
          return copy;
        });
        return updated;
      }

      setPassengerForms((current) => ({
        ...current,
        [seatNumber]: current[seatNumber] || { name: `Passenger ${selectedSeats.length + 1}`, age: "25", gender: "Other" }
      }));
      return [...prev, seatNumber].sort((a, b) => a - b);
    });
  };

  const updatePassengerForm = (seatNumber: number, field: keyof PassengerForm, value: string) => {
    setTravellerMessage("");
    setPassengerForms((prev) => ({
      ...prev,
      [seatNumber]: {
        ...prev[seatNumber],
        [field]: value
      }
    }));
  };

  const applySavedPassenger = (seatNumber: number, profileId: string) => {
    const profile = savedPassengers.find((item) => item.id === profileId);
    if (!profile) return;

    setPassengerForms((prev) => ({
      ...prev,
      [seatNumber]: {
        name: profile.name,
        age: String(profile.age),
        gender: profile.gender
      }
    }));
    setTravellerMessage(`Applied saved traveller to seat ${seatNumber}.`);
  };

  const savePassengerProfile = (seatNumber: number) => {
    const form = passengerForms[seatNumber];
    if (!form || !form.name.trim() || !form.age || Number(form.age) <= 0 || !form.gender) {
      setTravellerMessage("Enter valid passenger details before saving traveller info.");
      return;
    }

    const normalizedName = form.name.trim();
    const existing = savedPassengers.find(
      (profile) =>
        profile.name.toLowerCase() === normalizedName.toLowerCase() &&
        profile.age === Number(form.age) &&
        profile.gender === form.gender
    );

    if (existing) {
      setTravellerMessage(`${normalizedName} is already in saved travellers.`);
      return;
    }

    const nextProfiles = [
      ...savedPassengers,
      {
        id: `TRV${Date.now()}`,
        name: normalizedName,
        age: Number(form.age),
        gender: form.gender
      }
    ];

    persistSavedPassengers(nextProfiles);
    setTravellerMessage(`${normalizedName} saved for future bookings.`);
  };

  const removeSavedPassenger = (profileId: string) => {
    const nextProfiles = savedPassengers.filter((profile) => profile.id !== profileId);
    persistSavedPassengers(nextProfiles);
    setTravellerMessage("Saved traveller removed.");
  };

  const handleContinueToPayment = () => {
    if (!bus || !busId || !canContinueToPayment) return;

    const passengerDetails: PassengerDetail[] = selectedSeats.map((seatNumber) => ({
      seatNumber,
      name: passengerForms[seatNumber].name.trim(),
      age: Number(passengerForms[seatNumber].age),
      gender: passengerForms[seatNumber].gender
    }));

    navigate("/payment", {
      state: {
        busId,
        bus,
        travelDate,
        selectedSeats,
        passengerDetails,
        boardingPoint,
        droppingPoint,
        totalPrice
      }
    });
  };

  if (loading) {
    return <p className="text-slate-600">Loading seat layout...</p>;
  }

  if (!bus) {
    return <p className="text-slate-600">Bus not found.</p>;
  }

  return (
    <section className="grid gap-6 lg:grid-cols-[2fr_1fr]">
      <div className="space-y-6">
        <div className="rounded-2xl bg-white p-6 shadow-travel ring-1 ring-slate-200">
          <div className="mb-5 border-b border-slate-200 pb-4">
            <div className="flex flex-wrap items-start justify-between gap-4">
              <div>
                <h2 className="text-2xl font-bold text-slate-900">{bus.operatorName}</h2>
                <p className="mt-1 text-sm text-slate-600">{bus.departureCity} {"->"} {bus.arrivalCity}</p>
              </div>
              <div className="rounded-full bg-rose-50 px-4 py-2 text-sm font-semibold text-rose-600">Only {availableSeatCount} seats left</div>
            </div>
            <div className="mt-3 flex flex-wrap gap-x-5 gap-y-1 text-sm text-slate-600">
              {travelDate ? <span><strong>Date:</strong> {travelDate}</span> : null}
              <span><strong>Departure:</strong> {new Date(bus.departureTime).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}</span>
              <span><strong>Arrival:</strong> {new Date(bus.arrivalTime).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}</span>
              <span><strong>Seat Type:</strong> {bus.seatType}</span>
              <span><strong>{bus.isAC ? "AC" : "Non AC"}</strong></span>
            </div>
            <div className="mt-4 flex flex-wrap gap-2">
              {bus.amenities.map((amenity) => (
                <span key={amenity} className="rounded-full bg-slate-100 px-3 py-1 text-xs font-medium text-slate-700">{amenity}</span>
              ))}
            </div>
          </div>

          <div className="mb-6 grid gap-4 md:grid-cols-2">
            <div>
              <label className="mb-2 block text-sm font-semibold text-slate-900">Boarding Point</label>
              <select value={boardingPoint} onChange={(e) => setBoardingPoint(e.target.value)} className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none focus:border-blue-500">
                {bus.boardingPoints.map((point) => (
                  <option key={point} value={point}>{point}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="mb-2 block text-sm font-semibold text-slate-900">Dropping Point</label>
              <select value={droppingPoint} onChange={(e) => setDroppingPoint(e.target.value)} className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none focus:border-blue-500">
                {bus.droppingPoints.map((point) => (
                  <option key={point} value={point}>{point}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="mb-4 flex flex-wrap gap-4 text-xs sm:text-sm">
            <div className="flex items-center gap-2"><span className="h-3 w-3 rounded bg-emerald-500" />Available</div>
            <div className="flex items-center gap-2"><span className="h-3 w-3 rounded bg-blue-600" />Selected</div>
            <div className="flex items-center gap-2"><span className="h-3 w-3 rounded bg-slate-400" />Booked</div>
          </div>

          {seatLimitMessage ? <p className="mb-3 rounded-lg bg-amber-50 px-3 py-2 text-sm font-medium text-amber-700">{seatLimitMessage}</p> : null}

          <div className="space-y-2 rounded-xl border border-slate-200 bg-slate-50 p-4">
            {seatRows.map((row, rowIndex) => (
              <div key={`row-${rowIndex}`} className="grid grid-cols-[repeat(2,minmax(0,1fr))_2.25rem_repeat(2,minmax(0,1fr))] items-center gap-2">
                {row.slice(0, 2).map((seat) => {
                  const isSelected = selectedSeats.includes(seat.seatNumber);
                  const limitReached = selectedSeats.length >= MAX_SEATS && !isSelected;
                  const seatClass = !seat.isAvailable
                    ? "bg-slate-400 cursor-not-allowed"
                    : isSelected
                      ? "bg-blue-600 hover:bg-blue-700"
                      : limitReached
                        ? "bg-emerald-300 cursor-not-allowed"
                        : "bg-emerald-500 hover:bg-emerald-600";

                  return (
                    <button
                      key={seat.seatNumber}
                      type="button"
                      onClick={() => toggleSeat(seat.seatNumber, seat.isAvailable)}
                      disabled={!seat.isAvailable || limitReached}
                      className={`h-10 rounded-md text-xs font-semibold text-white shadow-sm transition sm:text-sm ${seatClass}`}
                    >
                      {seat.seatNumber}
                    </button>
                  );
                })}

                <div className="h-10 rounded border border-dashed border-slate-300" />

                {row.slice(2).map((seat) => {
                  const isSelected = selectedSeats.includes(seat.seatNumber);
                  const limitReached = selectedSeats.length >= MAX_SEATS && !isSelected;
                  const seatClass = !seat.isAvailable
                    ? "bg-slate-400 cursor-not-allowed"
                    : isSelected
                      ? "bg-blue-600 hover:bg-blue-700"
                      : limitReached
                        ? "bg-emerald-300 cursor-not-allowed"
                        : "bg-emerald-500 hover:bg-emerald-600";

                  return (
                    <button
                      key={seat.seatNumber}
                      type="button"
                      onClick={() => toggleSeat(seat.seatNumber, seat.isAvailable)}
                      disabled={!seat.isAvailable || limitReached}
                      className={`h-10 rounded-md text-xs font-semibold text-white shadow-sm transition sm:text-sm ${seatClass}`}
                    >
                      {seat.seatNumber}
                    </button>
                  );
                })}
              </div>
            ))}
          </div>
        </div>

        {selectedSeats.length > 0 ? (
          <div className="rounded-2xl bg-white p-6 shadow-travel ring-1 ring-slate-200">
            <div className="flex flex-wrap items-center justify-between gap-3">
              <h3 className="text-lg font-semibold text-slate-900">Passenger Details</h3>
              <p className="text-xs text-slate-500">Save frequent travellers and reuse them across bookings.</p>
            </div>

            {savedPassengers.length > 0 ? (
              <div className="mt-4 rounded-xl bg-slate-50 p-4 ring-1 ring-slate-200">
                <div className="flex flex-wrap items-center justify-between gap-3">
                  <p className="text-sm font-semibold text-slate-900">Saved Travellers</p>
                  <p className="text-xs text-slate-500">IRCTC-style traveller list for quick autofill</p>
                </div>
                <div className="mt-3 flex flex-wrap gap-3">
                  {savedPassengers.map((profile) => (
                    <div key={profile.id} className="rounded-xl bg-white px-4 py-3 text-sm ring-1 ring-slate-200">
                      <p className="font-semibold text-slate-900">{profile.name}</p>
                      <p className="text-slate-600">Age {profile.age} | {profile.gender}</p>
                      <button type="button" onClick={() => removeSavedPassenger(profile.id)} className="mt-2 text-xs font-semibold text-red-600">
                        Remove
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            ) : null}

            {travellerMessage ? <p className="mt-4 rounded-lg bg-blue-50 px-3 py-2 text-sm font-medium text-blue-700">{travellerMessage}</p> : null}

            <div className="mt-4 space-y-4">
              {selectedSeats.map((seatNumber) => (
                <div key={seatNumber} className="rounded-lg bg-slate-50 p-4 ring-1 ring-slate-200">
                  <div className="mb-3 flex flex-wrap items-center justify-between gap-3">
                    <p className="text-sm font-semibold text-slate-800">Seat {seatNumber}</p>
                    <div className="flex flex-wrap items-center gap-2">
                      {savedPassengers.length > 0 ? (
                        <select
                          defaultValue=""
                          onChange={(e) => {
                            if (e.target.value) {
                              applySavedPassenger(seatNumber, e.target.value);
                              e.target.value = "";
                            }
                          }}
                          className="rounded-lg border border-slate-300 px-3 py-2 text-xs outline-none focus:border-blue-500"
                        >
                          <option value="">Use saved traveller</option>
                          {savedPassengers.map((profile) => (
                            <option key={profile.id} value={profile.id}>{profile.name}</option>
                          ))}
                        </select>
                      ) : null}
                      <button
                        type="button"
                        onClick={() => savePassengerProfile(seatNumber)}
                        className="rounded-lg border border-blue-200 bg-blue-50 px-3 py-2 text-xs font-semibold text-blue-700"
                      >
                        Save Traveller
                      </button>
                    </div>
                  </div>
                  <div className="grid gap-3 md:grid-cols-3">
                    <input
                      type="text"
                      placeholder="Passenger Name"
                      value={passengerForms[seatNumber]?.name || ""}
                      onChange={(e) => updatePassengerForm(seatNumber, "name", e.target.value)}
                      className="rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none focus:border-blue-500"
                    />
                    <input
                      type="number"
                      min={1}
                      max={120}
                      placeholder="Age"
                      value={passengerForms[seatNumber]?.age || ""}
                      onChange={(e) => updatePassengerForm(seatNumber, "age", e.target.value)}
                      className="rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none focus:border-blue-500"
                    />
                    <select
                      value={passengerForms[seatNumber]?.gender || ""}
                      onChange={(e) => updatePassengerForm(seatNumber, "gender", e.target.value)}
                      className="rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none focus:border-blue-500"
                    >
                      <option value="">Select Gender</option>
                      <option value="Male">Male</option>
                      <option value="Female">Female</option>
                      <option value="Other">Other</option>
                    </select>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ) : null}
      </div>

      <aside className="h-fit rounded-2xl bg-white p-6 shadow-travel ring-1 ring-slate-200">
        <h3 className="text-lg font-semibold text-slate-900">Trip Summary</h3>
        <div className="mt-4 space-y-3 text-sm text-slate-700">
          <p><span className="font-medium">Operator:</span> {bus.operatorName}</p>
          <p><span className="font-medium">Route:</span> {bus.departureCity} {"->"} {bus.arrivalCity}</p>
          <p><span className="font-medium">Travel date:</span> {travelDate || "Select a date from search"}</p>
          <p><span className="font-medium">Boarding:</span> {boardingPoint || "Select boarding point"}</p>
          <p><span className="font-medium">Dropping:</span> {droppingPoint || "Select dropping point"}</p>
          <p className="flex items-center justify-between"><span>Price per seat</span><span className="font-semibold">INR {bus.price}</span></p>
          <p><span className="font-medium">Selected seats:</span> {selectedSeats.length ? selectedSeats.join(", ") : "None"}</p>
          <p className="flex items-center justify-between"><span>Passengers</span><span className="font-semibold">{selectedSeats.length}</span></p>
          <p className="flex items-center justify-between border-t border-slate-200 pt-3 text-base font-bold text-blue-700"><span>Total</span><span>INR {totalPrice}</span></p>
        </div>

        <button
          type="button"
          onClick={handleContinueToPayment}
          disabled={!canContinueToPayment}
          className="mt-5 w-full rounded-lg bg-blue-600 px-4 py-2.5 font-semibold text-white transition hover:bg-blue-700 disabled:cursor-not-allowed disabled:bg-blue-300"
        >
          Continue to Payment
        </button>
        {!canContinueToPayment ? (
          <p className="mt-2 text-xs text-slate-500">Select 1 to 4 seats, complete passenger details, and choose boarding and dropping points.</p>
        ) : null}
      </aside>
    </section>
  );
};

export default SeatSelectionPage;
